// ── Helpers ────────────────────────────────────────────────────────────────────

function fmtDate(d, t) {
	if (!d && !t) return null;
	if (d) {
		const [y, m, day] = d.split('-').map(Number);
		const dt = new Date(y, m - 1, day);
		const DAYS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
		const MONS = [
			'Jan',
			'Feb',
			'Mar',
			'Apr',
			'May',
			'Jun',
			'Jul',
			'Aug',
			'Sep',
			'Oct',
			'Nov',
			'Dec',
		];
		const suf = (n) =>
			[, 'st', 'nd', 'rd'][
				((n % 100) - 10) * ((n % 100) - 11) * ((n % 100) - 12) !== 0 &&
				n % 10 < 4
					? n % 10
					: 0
			] || 'th';
		let s = `${DAYS[dt.getDay()]}, ${MONS[dt.getMonth()]} ${day}`;
		if (t) {
			const [h, mi] = t.split(':').map(Number);
			s += ` • ${h % 12 || 12}:${String(mi).padStart(2, '0')} ${h >= 12 ? 'PM' : 'AM'}`;
		}
		return s;
	}
	if (t) {
		const [h, mi] = t.split(':').map(Number);
		return `${h % 12 || 12}:${String(mi).padStart(2, '0')} ${h >= 12 ? 'PM' : 'AM'}`;
	}
	return null;
}

function IconBubble({ iconUrl, bgColor, size = 42 }) {
	return (
		<div
			style={{
				width: size,
				height: size,
				borderRadius: '50%',
				background: bgColor,
				display: 'flex',
				alignItems: 'center',
				justifyContent: 'center',
				flexShrink: 0,
				overflow: 'hidden',
			}}>
			{iconUrl ? (
				<img
					src={iconUrl}
					alt=''
					style={{
						width: '70%',
						height: '70%',
						objectFit: 'contain',
						filter: 'brightness(0) invert(1)',
					}}
				/>
			) : (
				<Upload
					size={Math.round(size * 0.35)}
					color='rgba(255,255,255,0.5)'
					strokeWidth={1.8}
				/>
			)}
		</div>
	);
}

