function IconUpload({ iconUrl, bgColor, onChange }) {
	const inputRef = useRef(null);
	const [dragging, setDragging] = useState(false);

	const handleFile = (file) => {
		if (!file || !file.type.startsWith('image/')) return;
		const reader = new FileReader();
		reader.onload = (e) => {
			const img = new Image();
			img.onload = () => {
				const canvas = document.createElement('canvas');
				canvas.width = img.width;
				canvas.height = img.height;
				const ctx = canvas.getContext('2d');
				ctx.drawImage(img, 0, 0);
				// Convert every non-transparent pixel to white
				const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
				const d = imageData.data;
				for (let i = 0; i < d.length; i += 4) {
					if (d[i + 3] > 10) {
						// skip nearly-transparent pixels
						d[i] = 255;
						d[i + 1] = 255;
						d[i + 2] = 255;
					}
				}
				ctx.putImageData(imageData, 0, 0);
				onChange(canvas.toDataURL('image/png'));
			};
			img.src = e.target.result;
		};
		reader.readAsDataURL(file);
	};

	return (
		<div>
			<div
				onClick={() => inputRef.current.click()}
				onDragOver={(e) => {
					e.preventDefault();
					setDragging(true);
				}}
				onDragLeave={() => setDragging(false)}
				onDrop={(e) => {
					e.preventDefault();
					setDragging(false);
					handleFile(e.dataTransfer.files[0]);
				}}
				style={{
					border: `2px dashed ${dragging ? FLYER_HDR : '#d0ccc4'}`,
					borderRadius: 8,
					padding: '12px 10px',
					display: 'flex',
					alignItems: 'center',
					gap: 12,
					cursor: 'pointer',
					background: dragging ? '#f0f7f4' : 'white',
					transition: 'all 0.15s',
				}}>
				{/* Preview bubble */}
				<IconBubble iconUrl={iconUrl} bgColor={bgColor} size={44} />

				<div style={{ flex: 1 }}>
					{iconUrl ? (
						<div
							style={{
								fontSize: 12,
								fontWeight: 600,
								color: FLYER_HDR,
							}}>
							Icon uploaded
						</div>
					) : (
						<div
							style={{
								fontSize: 12,
								fontWeight: 600,
								color: '#888',
							}}>
							Click or drag to upload
						</div>
					)}
					<div style={{ fontSize: 10.5, color: '#bbb', marginTop: 2 }}>
						PNG, SVG, JPG — white/transparent works best
					</div>
				</div>

				{iconUrl && (
					<button
						onClick={(e) => {
							e.stopPropagation();
							onChange(null);
						}}
						style={{
							background: '#fef2f2',
							border: '1px solid #f5c6c6',
							borderRadius: 5,
							color: '#c0392b',
							cursor: 'pointer',
							padding: '4px 7px',
							fontSize: 11,
							fontWeight: 700,
							flexShrink: 0,
						}}>
						<X size={12} strokeWidth={2.5} />
					</button>
				)}
			</div>
			<input
				ref={inputRef}
				type='file'
				accept='image/*'
				style={{ display: 'none' }}
				onChange={(e) => handleFile(e.target.files[0])}
			/>
		</div>
	);
}

function JKMultiSelect({ value, onChange }) {
	const [open, setOpen] = useState(false);
	const ref = useRef(null);

	useEffect(() => {
		const h = (e) => {
			if (ref.current && !ref.current.contains(e.target)) setOpen(false);
		};
		document.addEventListener('mousedown', h);
		return () => document.removeEventListener('mousedown', h);
	}, []);

	const toggle = (jk) =>
		onChange(
			value.includes(jk) ? value.filter((j) => j !== jk) : [...value, jk],
		);

	return (
		<div ref={ref} style={{ position: 'relative' }}>
			<button
				onClick={() => setOpen((o) => !o)}
				style={{
					...INP,
					display: 'flex',
					alignItems: 'center',
					cursor: 'pointer',
					border: '1px solid #d8d4cc',
					padding: '7px 10px',
					gap: 6,
				}}>
				<span
					style={{
						flex: 1,
						textAlign: 'left',
						fontSize: 12,
						color: value.length ? '#222' : '#aaa',
						overflow: 'hidden',
						textOverflow: 'ellipsis',
						whiteSpace: 'nowrap',
					}}>
					{value.length === 0
						? 'Select Jamatkhanas…'
						: value.length <= 2
							? value.join(', ')
							: `${value[0]}, +${value.length - 1} more`}
				</span>
				{value.length > 0 && (
					<span
						style={{
							background: FLYER_HDR,
							color: 'white',
							borderRadius: 10,
							fontSize: 10,
							fontWeight: 700,
							padding: '1px 7px',
							flexShrink: 0,
						}}>
						{value.length}
					</span>
				)}
				<ChevronDown size={13} color='#888' />
			</button>

			{open && (
				<div
					style={{
						position: 'absolute',
						top: 'calc(100% + 4px)',
						left: 0,
						right: 0,
						zIndex: 200,
						background: 'white',
						border: '1px solid #d8d4cc',
						borderRadius: 8,
						boxShadow: '0 6px 20px rgba(0,0,0,0.15)',
						overflow: 'hidden',
					}}>
					<div
						style={{
							display: 'flex',
							gap: 0,
							borderBottom: '1px solid #f0ede6',
						}}>
						{['All', 'Clear'].map((lbl, i) => (
							<button
								key={lbl}
								onClick={() => onChange(i === 0 ? [...JK_OPTIONS] : [])}
								style={{
									flex: 1,
									padding: '7px 0',
									border: 'none',
									background: '#fafaf7',
									fontSize: 11,
									color: i === 0 ? FLYER_HDR : '#888',
									cursor: 'pointer',
									fontWeight: 600,
								}}>
								{lbl}
							</button>
						))}
					</div>
					<div style={{ maxHeight: 230, overflowY: 'auto' }}>
						{JK_OPTIONS.map((jk) => {
							const on = value.includes(jk);
							return (
								<div
									key={jk}
									onClick={() => toggle(jk)}
									style={{
										display: 'flex',
										alignItems: 'center',
										gap: 9,
										padding: '8px 12px',
										cursor: 'pointer',
										fontSize: 12.5,
										background: on ? '#eef5f1' : 'white',
										borderBottom: '1px solid #f7f6f0',
									}}>
									<div
										style={{
											width: 15,
											height: 15,
											borderRadius: 3,
											flexShrink: 0,
											border: `1.5px solid ${on ? FLYER_HDR : '#ccc'}`,
											background: on ? FLYER_HDR : 'white',
											display: 'flex',
											alignItems: 'center',
											justifyContent: 'center',
										}}>
										{on && <Check size={9} color='white' strokeWidth={3} />}
									</div>
									{jk}
								</div>
							);
						})}
					</div>
				</div>
			)}
		</div>
	);
}

