// ── Main App ───────────────────────────────────────────────────────────────────

export default function FlyerApp() {
	const [announcements, setAnnouncements] = useState(SAMPLE);
	const [form, setForm] = useState({ ...DEFAULT_FORM });
	const [editingId, setEditingId] = useState(null);
	const [activeTab, setActiveTab] = useState('add');
	const [headerTitle, setHeaderTitle] = useState('LOCAL ANNOUNCEMENTS');
	const [headerSubtitle, setHeaderSubtitle] = useState('Friday, April 3, 2026');
	const [footerUrl, setFooterUrl] = useState('https://tinyurl.com/SEWeekly');

	console.log(announcements);

	const [exporting, setExporting] = useState(null);
	const [overflowError, setOverflowError] = useState(false);
	const [pendingId, setPendingId] = useState(null); // id of newly-added item to verify

	const previewRef = useRef(null);
	const bodyRef = useRef(null); // ref on the body overflow:hidden div inside FlyerPreview

	// ── Measure-then-rollback after every add ──────────────────────────────────
	// Runs synchronously after DOM paint so the user never sees the flash
	useLayoutEffect(() => {
		if (pendingId === null || !bodyRef.current) return;
		const el = bodyRef.current;
		if (el.scrollHeight > el.clientHeight) {
			// Overflows — revert the add, show error
			setAnnouncements((prev) => prev.filter((a) => a.id !== pendingId));
			setOverflowError(true);
			setActiveTab('add'); // bounce back to form so user sees the error
		} else {
			setOverflowError(false);
		}
		setPendingId(null);
	}, [pendingId, announcements]);

	// Clear overflow error when user removes an announcement
	useEffect(() => {
		if (overflowError && bodyRef.current) {
			const el = bodyRef.current;
			if (el.scrollHeight <= el.clientHeight) setOverflowError(false);
		}
	}, [announcements, overflowError]);

	// Load export libs
	useEffect(() => {
		const load = (src, cb) => {
			if (document.querySelector(`script[src="${src}"]`)) {
				cb && cb();
				return;
			}
			const s = document.createElement('script');
			s.src = src;
			s.onload = cb;
			document.head.appendChild(s);
		};
		load(
			'https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js',
			() =>
				load(
					'https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js',
				),
		);
	}, []);

	const handleSubmit = useCallback(() => {
		if (!form.title.trim()) return;
		if (editingId !== null) {
			setAnnouncements((prev) =>
				prev.map((a) => (a.id === editingId ? { ...form, id: editingId } : a)),
			);
			setEditingId(null);
			setForm({ ...DEFAULT_FORM });
			setActiveTab('list');
		} else {
			const newId = Date.now();
			setAnnouncements((prev) => [...prev, { ...form, id: newId }]);
			setPendingId(newId); // triggers the layout check
			setForm({ ...DEFAULT_FORM });
			setActiveTab('list');
		}
	}, [form, editingId]);

	const handleEdit = useCallback((ann) => {
		setForm({ ...ann });
		setEditingId(ann.id);
		setActiveTab('add');
	}, []);

	const handleDelete = useCallback(
		(id) => {
			setAnnouncements((prev) => prev.filter((a) => a.id !== id));
			if (editingId === id) {
				setEditingId(null);
				setForm({ ...DEFAULT_FORM });
			}
		},
		[editingId],
	);

	const handleCancel = useCallback(() => {
		setEditingId(null);
		setForm({ ...DEFAULT_FORM });
	}, []);

	const handleExport = async (fmt) => {
		if (!window.html2canvas || !previewRef.current) {
			alert(
				'Export libraries still loading. Please wait a moment and try again.',
			);
			return;
		}
		setExporting(fmt);
		try {
			const canvas = await window.html2canvas(previewRef.current, {
				scale: 2,
				useCORS: true,
				allowTaint: true,
				backgroundColor: FLYER_BG,
				logging: false,
			});
			if (fmt === 'pdf') {
				const { jsPDF } = window.jspdf;
				const w = canvas.width / 2,
					h = canvas.height / 2;
				const pdf = new jsPDF({
					orientation: w > h ? 'landscape' : 'portrait',
					unit: 'px',
					format: [w, h],
				});
				pdf.addImage(canvas.toDataURL('image/jpeg', 0.95), 'JPEG', 0, 0, w, h);
				pdf.save('announcement-flyer.pdf');
			} else {
				const a = document.createElement('a');
				a.download = `announcement-flyer.${fmt}`;
				a.href = canvas.toDataURL(`image/${fmt}`, 0.95);
				a.click();
			}
		} catch (e) {
			alert('Export failed: ' + e.message);
		}
		setExporting(null);
	};

	const TABS = [
		{
			id: 'add',
			label: editingId ? '✏ Edit' : '+ Add',
			disabled: overflowError && !editingId,
		},
		{ id: 'list', label: `≡ List (${announcements.length})` },
		{ id: 'settings', label: '⚙ Settings' },
	];

	return (
		<div
			style={{
				display: 'flex',
				height: '100vh',
				background: '#1a1a1a',
				fontFamily: GOTHAM,
				overflow: 'hidden',
			}}>
			{/* ── Left Panel ── */}
			<div
				style={{
					width: 360,
					background: '#faf9f5',
					display: 'flex',
					flexDirection: 'column',
					boxShadow: '2px 0 12px rgba(0,0,0,0.2)',
					zIndex: 10,
					flexShrink: 0,
				}}>
				{/* Panel Header */}
				<div
					style={{
						background: FLYER_HDR,
						padding: '14px 16px 12px',
					}}>
					<div
						style={{
							color: 'white',
							fontWeight: 800,
							fontSize: 15,
							letterSpacing: 0.5,
						}}>
						Flyer Builder
					</div>
					<div
						style={{
							color: 'rgba(255,255,255,0.55)',
							fontSize: 10.5,
							marginTop: 2,
							letterSpacing: 1.5,
							textTransform: 'uppercase',
						}}>
						Ismaili Council — Southeast USA
					</div>
				</div>

				{/* Tabs */}
				<div
					style={{
						display: 'flex',
						background: 'white',
						borderBottom: '1px solid #e5e2d8',
					}}>
					{TABS.map((tab) => (
						<button
							key={tab.id}
							onClick={() => !tab.disabled && setActiveTab(tab.id)}
							style={{
								flex: 1,
								padding: '9px 0',
								border: 'none',
								cursor: tab.disabled ? 'not-allowed' : 'pointer',
								background: activeTab === tab.id ? '#f0f7f4' : 'white',
								color: tab.disabled
									? '#ccc'
									: activeTab === tab.id
										? FLYER_HDR
										: '#777',
								fontWeight: activeTab === tab.id ? 700 : 400,
								fontSize: 11.5,
								borderBottom:
									activeTab === tab.id
										? `2px solid ${FLYER_HDR}`
										: '2px solid transparent',
							}}>
							{tab.label}
						</button>
					))}
				</div>

				{/* Scrollable content */}
				<div style={{ flex: 1, overflowY: 'auto', padding: 16 }}>
					{/* ── OVERFLOW WARNING — replaces Add form when flyer is too full ── */}
					{overflowError && activeTab === 'add' && !editingId ? (
						<div
							style={{
								display: 'flex',
								flexDirection: 'column',
								alignItems: 'center',
								justifyContent: 'center',
								height: '100%',
								gap: 16,
								padding: '24px 8px',
								textAlign: 'center',
							}}>
							<div style={{ fontSize: 40 }}>📄</div>
							<div
								style={{
									fontWeight: 800,
									fontSize: 15,
									color: '#c0392b',
									letterSpacing: 0.3,
									fontFamily: GOTHAM,
								}}>
								Announcement Doesn't Fit
							</div>
							<div
								style={{
									fontSize: 12,
									color: '#888',
									lineHeight: 1.6,
									fontFamily: GOTHAM,
								}}>
								That announcement was <strong>too large</strong> for the
								remaining space and was not added. The flyer is locked to{' '}
								<strong>US Letter size</strong> (8.5" × 11").
							</div>
							<div
								style={{
									background: '#fef2f2',
									border: '1px solid #f5c6c6',
									borderRadius: 8,
									padding: '12px 16px',
									width: '100%',
									textAlign: 'left',
								}}>
								<div
									style={{
										fontSize: 11,
										fontWeight: 700,
										color: '#c0392b',
										marginBottom: 6,
										fontFamily: GOTHAM,
									}}>
									To make room:
								</div>
								<div
									style={{
										fontSize: 11,
										color: '#666',
										lineHeight: 1.8,
										fontFamily: GOTHAM,
									}}>
									• <strong>Remove</strong> an existing announcement from the
									List tab
									<br />• <strong>Shorten</strong> a description to free up
									vertical space
									<br />• <strong>Export</strong> this flyer and start a new one
								</div>
							</div>
							<button
								onClick={() => setActiveTab('list')}
								style={{
									width: '100%',
									padding: '10px 0',
									background: FLYER_HDR,
									color: 'white',
									border: 'none',
									borderRadius: 6,
									fontWeight: 700,
									fontSize: 13,
									cursor: 'pointer',
									fontFamily: GOTHAM,
									letterSpacing: 0.3,
								}}>
								Manage Announcements →
							</button>
						</div>
					) : (
						<>
							{activeTab === 'add' && (
								<AnnouncementForm
									form={form}
									setForm={setForm}
									onSubmit={handleSubmit}
									isEditing={editingId !== null}
									onCancel={handleCancel}
								/>
							)}
							{activeTab === 'list' && (
								<AnnouncementList
									announcements={announcements}
									onEdit={handleEdit}
									onDelete={handleDelete}
								/>
							)}
							{activeTab === 'settings' && (
								<SettingsPanel
									headerTitle={headerTitle}
									setHeaderTitle={setHeaderTitle}
									headerSubtitle={headerSubtitle}
									setHeaderSubtitle={setHeaderSubtitle}
									footerUrl={footerUrl}
									setFooterUrl={setFooterUrl}
								/>
							)}
						</>
					)}
				</div>

				{/* Export Row */}
				<div
					style={{
						padding: '12px 14px',
						borderTop: '1px solid #e5e2d8',
						background: 'white',
					}}>
					<div
						style={{
							fontSize: 10,
							color: '#aaa',
							marginBottom: 7,
							letterSpacing: 1,
							textTransform: 'uppercase',
							fontWeight: 600,
						}}>
						Export Flyer
					</div>
					<div style={{ display: 'flex', gap: 7 }}>
						{['PNG', 'JPEG', 'PDF'].map((fmt) => (
							<button
								key={fmt}
								onClick={() => handleExport(fmt.toLowerCase())}
								disabled={!!exporting}
								style={{
									flex: 1,
									padding: '9px 0',
									border: 'none',
									borderRadius: 6,
									cursor: exporting ? 'default' : 'pointer',
									background:
										exporting === fmt.toLowerCase() ? '#7aab95' : FLYER_HDR,
									color: 'white',
									fontWeight: 700,
									fontSize: 12,
									letterSpacing: 0.5,
									transition: 'background 0.2s',
								}}>
								{exporting === fmt.toLowerCase() ? '…' : `↓ ${fmt}`}
							</button>
						))}
					</div>
				</div>
			</div>

			{/* ── Right Panel (Preview) ── */}
			<div
				style={{
					flex: 1,
					overflowY: 'auto',
					padding: '32px 40px',
					display: 'flex',
					flexDirection: 'column',
					alignItems: 'center',
				}}>
				<div
					style={{
						marginBottom: 12,
						color: 'rgba(255,255,255,0.4)',
						fontSize: 10,
						letterSpacing: 2,
						textTransform: 'uppercase',
					}}>
					Live Preview — US Letter (8.5" × 11")
				</div>
				<div
					ref={previewRef}
					style={{
						boxShadow: '0 8px 40px rgba(0,0,0,0.5)',
						borderRadius: 2,
						flexShrink: 0,
					}}>
					<FlyerPreview
						announcements={announcements}
						headerTitle={headerTitle}
						headerSubtitle={headerSubtitle}
						footerUrl={footerUrl}
						bodyRef={bodyRef}
					/>
				</div>
				<div style={{ height: 40 }} />
			</div>
		</div>
	);
}
